mapper.select:
SELECT a.*, COALESCE(b.sys09_code, '') AS sys13_code, COALESCE(b.sys09_name, '') AS sys13_name
  FROM sys13_code_group a
       LEFT OUTER JOIN sys09_code b ON a.sys13_code_id = b.sys09_code_id
 WHERE sys13_kind_group_cd = #{kindGroupCode}
   AND sys13_code_kind_id  = #{codeKindId}
   AND sys13_code_id != 0
   AND sys09_company_id = #{companyId}

mapper.update:
UPDATE sys13_code_group
   SET sys13_kind_group_cd = #{kindGroupCode},
       sys13_kind_group_nm = #{kindGroupName}
 WHERE sys13_code_kind_id  = #{codeKindId}
   AND sys13_kind_group_cd = #{kindGroupCode}
   AND sys13_kind_group_nm = #{kindGroupName}

mapper.delete:
DELETE FROM sys13_code_group
 WHERE sys13_code_kind_id  = #{codeKindId}
   AND sys13_kind_group_cd = #{kindGroupCode}
   AND sys13_kind_group_nm = #{kindGroupName}
